using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using System.IO;

public class FilesController : Controller
{
    private readonly IWebHostEnvironment _environment;
    private readonly string _uploadsFolder;

    public FilesController(IWebHostEnvironment environment)
    {
        _environment = environment;
        
        // Define the path to the uploads folder. 
        // We'll place it directly under the application's content root.
        // For example, if your project is at C:\MyWebApp, the uploads folder will be C:\MyWebApp\uploads
        _uploadsFolder = Path.Combine(_environment.ContentRootPath, "uploads");

        // Ensure the uploads directory exists.
        // In a production environment, this folder would typically be pre-created
        // and possibly outside the application deployment directory for persistence.
        if (!Directory.Exists(_uploadsFolder))
        {
            Directory.CreateDirectory(_uploadsFolder);
        }
    }

    [HttpGet("files/{filename}")]
    public IActionResult GetFile(string filename)
    {
        if (string.IsNullOrWhiteSpace(filename))
        {
            return BadRequest("Filename cannot be empty.");
        }

        // IMPORTANT SECURITY: Prevent directory traversal attacks.
        // Path.GetFileName extracts only the file name from a path,
        // ignoring any directory separators like '../'.
        string safeFilename = Path.GetFileName(filename);
        string filePath = Path.Combine(_uploadsFolder, safeFilename);

        // Check if the file exists
        if (!System.IO.File.Exists(filePath))
        {
            return NotFound();
        }

        // Determine the content type (MIME type) of the file
        var provider = new FileExtensionContentTypeProvider();
        string contentType;
        if (!provider.TryGetContentType(filePath, out contentType))
        {
            // Fallback to a generic binary stream if the content type cannot be determined
            contentType = "application/octet-stream";
        }

        // Serve the file directly using PhysicalFileResult for efficiency.
        // The last parameter (safeFilename) suggests a download filename for the browser, which is optional.
        return PhysicalFile(filePath, contentType, safeFilename);
    }
}